def _timeline_transcript(tl, *, with_timecodes=False):
    """Read a timeline's subtitle track(s) as transcript text."""
    try:
        track_count = tl.GetTrackCount("subtitle")
    except Exception:
        track_count = 0
    cues: List[Dict[str, Any]] = []
    for ti in range(1, (track_count or 0) + 1):
        for item in (tl.GetItemListInTrack("subtitle", ti) or []):
            text = ""
            try:
                text = item.GetName() or ""
            except Exception:
                text = ""
            cue = {"text": text}
            if with_timecodes:
                try:
                    cue["start"] = item.GetStart()
                    cue["end"] = item.GetEnd()
                except Exception:
                    pass
            cues.append(cue)
    full = " ".join(c["text"] for c in cues if c.get("text"))
    return {
        "text": full,
        "cue_count": len(cues),
        "has_subtitles": bool(cues),
        "cues": cues,
    }

def _copy_voice_isolation(source_item, duplicate_item):
    getter = getattr(source_item, "GetVoiceIsolationState", None)
    setter = getattr(duplicate_item, "SetVoiceIsolationState", None)
    if not callable(getter) or not callable(setter):
        return {"success": True, "copied": False, "reason": "voice isolation API unavailable"}
    try:
        state = getter()
    except Exception as exc:
        return {"success": False, "error": f"GetVoiceIsolationState failed: {exc}"}
    if not state:
        state = {"isEnabled": False, "amount": 0}
    try:
        return {"success": bool(setter(state)), "state": _ser(state)}
    except Exception as exc:
        return {"success": False, "state": _ser(state), "error": f"SetVoiceIsolationState failed: {exc}"}

def _variant_audio_summary(built):
    """Video/audio range counts for an assembled variant, warning when it carries
    no audio. create_variant_from_ranges places exactly the ranges given, so a
    video-only range list yields a silent timeline."""
    video = sum(1 for row in built if row.get("media_type") == 1)
    audio = sum(1 for row in built if row.get("media_type") == 2)
    summary = {"video_ranges": video, "audio_ranges": audio}
    if audio == 0:
        summary["warning"] = "video-only (no audio): add ranges with track_type='audio' to carry sound"
    return summary

def _audio_mix_capability_report(proj, mp, tl, p: Dict[str, Any]) -> Dict[str, Any]:
    report = _fairlight_boundary_report(proj, mp, tl, p)
    item = report.get("item") or {}
    audio_props = item.get("audio_properties") or {}
    unavailable = [key for key, value in audio_props.items() if value is None or isinstance(value, dict)]
    report["mix_recommendations"] = {
        "item_property_writes": "probe_with_safe_set_audio_properties_before relying on item-level Volume/Pan changes",
        "unavailable_or_readonly_probe_values": unavailable,
        "fallbacks": [
            "Use track enable/lock/name and voice-isolation helpers where available.",
            "Use project_settings.apply_fairlight_preset when an approved Fairlight preset exists.",
            "Use manual Fairlight mixing for detailed levels, pans, automation curves, and plugin parameters.",
            "Add separate sound-design assets only when the user explicitly requests imports or media changes.",
        ],
    }
    return report

def _timeline_set_clip_volume_impl(proj, tl, p: Dict[str, Any]):
    """3.2.1 (issue #22): the t14 DRT volume-automation writer, generalized into a
    standalone `timeline` action (it previously only ran inside auto_edit's ducking
    pipeline). Same export->drp-ops->reimport round trip as the Stage 3.1 actions.
    """
    from src.domains.timeline_edit.actions import _advanced_edit_resolve_clip, _advanced_timeline_edit
    track_type, track_index, clip_index, _item, err = _advanced_edit_resolve_clip(tl, p)
    if err:
        return err
    if track_type != "audio":
        return _err(f"set_clip_volume only supports audio clips (got {track_type!r})")
    volume_db = p.get("volume_db", p.get("volumeDb"))
    if volume_db is None:
        return _err("set_clip_volume requires volume_db")
    try:
        volume_db = float(volume_db)
    except (TypeError, ValueError):
        return _err("volume_db must be a number")

    return _advanced_timeline_edit(
        proj, tl, p,
        action_name="set_clip_volume",
        ops=[{"op": "set_audio_level", "args": {
            "track": track_index, "volumeDb": volume_db, "clipIndex": clip_index}}],
        warning=(
            "Exports the current timeline as .drt, writes the clip's audio-volume "
            "EffectFiltersBA (the scripting API has no clip-volume write path) via offline "
            "drt surgery, and imports a NEW '(edited)' timeline. No existing timeline is "
            "modified. Verify the audible result with a render probe."
        ),
    )

