def _audio_track_probe(tl, p: Dict[str, Any]):
    track_index = int(p.get("track_index", 1))
    track_count = int(tl.GetTrackCount("audio") or 0)
    # Resolve audio tracks are 1-indexed; track_index < 1 is invalid (EX11 — the
    # old `track_index <= track_count` reported available:true for index 0).
    out = {"track_index": track_index, "track_count": track_count,
           "available": 1 <= track_index <= track_count}
    if not (1 <= track_index <= track_count):
        return out
    for key, getter, args in (
        ("sub_type", "GetTrackSubType", ("audio", track_index)),
        ("name", "GetTrackName", ("audio", track_index)),
        ("enabled", "GetIsTrackEnabled", ("audio", track_index)),
        ("locked", "GetIsTrackLocked", ("audio", track_index)),
    ):
        method = getattr(tl, getter, None)
        if callable(method):
            try:
                out[key] = _ser(method(*args))
            except Exception as exc:
                out[f"{key}_error"] = str(exc)
    if _has_method(tl, "GetVoiceIsolationState"):
        try:
            out["voice_isolation"] = _ser(tl.GetVoiceIsolationState(track_index) or {"isEnabled": False, "amount": 0})
        except Exception as exc:
            out["voice_isolation_error"] = str(exc)
    else:
        out["voice_isolation_available"] = False
    return out

def _audio_item_from_params(tl, p: Dict[str, Any]):
    track_type = p.get("track_type", "audio")
    track_index = int(p.get("track_index", 1))
    item_index = int(p.get("item_index", 0))
    items = tl.GetItemListInTrack(track_type, track_index) or []
    if item_index < 0 or item_index >= len(items):  # reject negatives (EX5)
        return None, _err(f"No item at index {item_index} on {track_type} track {track_index}")
    return items[item_index], None

def _timeline_item_audio_snapshot(item):
    props = {}
    for key in _AUDIO_PROPERTY_KEYS:
        try:
            props[key] = item.GetProperty(key)
        except Exception as exc:
            props[key] = {"error": str(exc)}
    source_mapping = None
    source_mapping_error = None
    if _has_method(item, "GetSourceAudioChannelMapping"):
        try:
            source_mapping = _ser(item.GetSourceAudioChannelMapping())
        except Exception as exc:
            source_mapping_error = str(exc)
    voice = None
    voice_error = None
    if _has_method(item, "GetVoiceIsolationState"):
        try:
            voice = _ser(item.GetVoiceIsolationState() or {"isEnabled": False, "amount": 0})
        except Exception as exc:
            voice_error = str(exc)
    return {
        "summary": _timeline_item_summary(item),
        "audio_properties": props,
        "source_audio_mapping": {"value": source_mapping, "error": source_mapping_error} if source_mapping_error else source_mapping,
        "voice_isolation": {"value": voice, "error": voice_error} if voice_error else voice,
        "methods": _callable_method_names(
            item,
            ["GetProperty", "SetProperty", "GetSourceAudioChannelMapping", "GetVoiceIsolationState", "SetVoiceIsolationState"],
        ),
    }

def _probe_audio_item(tl, p: Dict[str, Any]):
    item, err = _audio_item_from_params(tl, p)
    if err:
        return err
    return _timeline_item_audio_snapshot(item)

def _safe_set_audio_properties(tl, p: Dict[str, Any]):
    item, err = _audio_item_from_params(tl, p)
    if err:
        return err
    properties = p.get("properties")
    if properties is None:
        properties = {key: p[key] for key in _AUDIO_PROPERTY_KEYS if key in p}
    if not isinstance(properties, dict) or not properties:
        return _err("properties must be a non-empty object or pass one of Volume, Pan, AudioSyncOffsetIsManual, AudioSyncOffset")
    invalid = [key for key in properties if key not in _AUDIO_PROPERTY_KEYS]
    if invalid:
        return _err(f"Unsupported audio propertie(s): {', '.join(invalid)}")
    original = {}
    for key in properties:
        try:
            original[key] = item.GetProperty(key)
        except Exception as exc:
            original[key] = {"error": str(exc)}
    if p.get("dry_run"):
        return _ok(would_set=properties, original=original)
    results = {}
    for key, value in properties.items():
        row = {"requested": value, "original": original.get(key)}
        try:
            row["write"] = bool(item.SetProperty(key, value))
        except Exception as exc:
            row["write"] = False
            row["error"] = str(exc)
        try:
            row["readback"] = item.GetProperty(key)
        except Exception as exc:
            row["readback_error"] = str(exc)
        if p.get("restore", True) and not isinstance(original.get(key), dict):
            try:
                row["restore"] = bool(item.SetProperty(key, original[key]))
            except Exception as exc:
                row["restore"] = False
                row["restore_error"] = str(exc)
        results[key] = row
    return {"success": all(row.get("write") for row in results.values()), "results": results}

def _voice_isolation_capabilities(tl, p: Dict[str, Any]):
    out = {
        "timeline_track": {
            "get_available": _has_method(tl, "GetVoiceIsolationState"),
            "set_available": _has_method(tl, "SetVoiceIsolationState"),
        },
        "item": None,
    }
    if out["timeline_track"]["get_available"]:
        try:
            out["timeline_track"]["state"] = _ser(tl.GetVoiceIsolationState(int(p.get("track_index", 1))) or {"isEnabled": False, "amount": 0})
        except Exception as exc:
            out["timeline_track"]["error"] = str(exc)
    item, item_err = _audio_item_from_params(tl, p)
    if item_err:
        out["item"] = {"available": False, "error": item_err.get("error")}
    else:
        out["item"] = {
            "get_available": _has_method(item, "GetVoiceIsolationState"),
            "set_available": _has_method(item, "SetVoiceIsolationState"),
        }
        if out["item"]["get_available"]:
            try:
                out["item"]["state"] = _ser(item.GetVoiceIsolationState() or {"isEnabled": False, "amount": 0})
            except Exception as exc:
                out["item"]["error"] = str(exc)
    return out

def _audio_mapping_report(mp, tl, p: Dict[str, Any]):
    from src.domains.media_pool_ingest.actions import _media_pool_item_summary
    root = mp.GetRootFolder()
    timeline_items = []
    for track_type in ("video", "audio"):
        for track_index in range(1, int(tl.GetTrackCount(track_type) or 0) + 1):
            for item_index, item in enumerate(tl.GetItemListInTrack(track_type, track_index) or []):
                row = _timeline_item_summary(item, (track_type, track_index)) or {}
                row["item_index"] = item_index
                if _has_method(item, "GetSourceAudioChannelMapping"):
                    try:
                        row["source_audio_mapping"] = _ser(item.GetSourceAudioChannelMapping())
                    except Exception as exc:
                        row["source_audio_mapping_error"] = str(exc)
                timeline_items.append(row)
    clip_rows = []
    ids = p.get("clip_ids")
    clips = []
    if ids:
        if not isinstance(ids, list):
            return _err("clip_ids must be a list")
        clips = [_find_clip(root, str(clip_id)) for clip_id in ids]
        clips = [clip for clip in clips if clip]
    else:
        seen = set()
        for row in timeline_items:
            clip_id = row.get("media_pool_item_id")
            if clip_id and clip_id not in seen:
                clip = _find_clip(root, clip_id)
                if clip:
                    clips.append(clip)
                    seen.add(clip_id)
    for clip in clips:
        mapping, mapping_error = _safe_clip_call(clip, "GetAudioMapping")
        clip_rows.append({
            "summary": _media_pool_item_summary(clip),
            "audio_mapping": {"value": mapping, "error": mapping_error} if mapping_error else mapping,
        })
    return {"timeline_items": timeline_items, "media_pool_items": clip_rows}

def _synced_audio(clip):
    """Best-effort read of whether a clip currently has synced audio linked."""
    try:
        v = clip.GetClipProperty("Synced Audio")
    except Exception:
        return False
    return bool(v) and str(v).strip() not in ("", "None", "0", "Off", "No")

def _safe_auto_sync_audio(mp, p: Dict[str, Any]):
    root = mp.GetRootFolder()
    resolved, err = _clips_from_params(root, mp, p)
    if err:
        return err
    clips, missing = resolved
    # Use get_resolve() rather than the module global `resolve`, which is None
    # until populated and can be reset to None by a mid-call reconnect. A None
    # here makes _normalize_auto_sync_settings fall back to string enum keys,
    # which AutoSyncAudio silently rejects (returns False).
    settings, ignored_settings = _normalize_auto_sync_settings(dict(p.get("settings") or {}), get_resolve())
    if p.get("dry_run", True):
        return _ok(would_auto_sync=True, clips=_clip_summaries(clips), missing=missing, settings=settings, ignored_settings=ignored_settings)
    # Read-back verification: AutoSyncAudio's boolean return is unreliable, so
    # capture each clip's "Synced Audio" linkage before and after and report the
    # delta. Trust `linked`/`newly_linked`, not `success`.
    def _categorize(before, observed):
        linked, newly, already = [], [], []
        for c, was, now in zip(clips, before, observed):
            if now:
                name = _clip_name(c)
                linked.append(name)
                (already if was else newly).append(name)
        return {
            "linked": linked,
            "newly_linked": newly,
            "already_linked": already,
            "verified": bool(linked),
        }

    res = verify_by_readback(
        mutate=lambda: mp.AutoSyncAudio(clips, settings),
        observe=lambda: [_synced_audio(c) for c in clips],
        snapshot=lambda: [_synced_audio(c) for c in clips],
        compare=_categorize,
        label="auto_sync_audio",
        intent={"clip_count": len(clips)},
    )
    return {
        "success": res["success_raw"],
        "verified": res["verified"],
        "linked": res["linked"],
        "newly_linked": res["newly_linked"],
        "already_linked": res["already_linked"],
        "count": len(clips),
        "missing": missing,
        "settings": settings,
        "ignored_settings": ignored_settings,
    }

def _normalize_auto_sync_settings(settings: Dict[str, Any], resolve_obj=None):
    """Translate human-readable AutoSyncAudio settings into live ``AUDIO_SYNC_*``
    enum keys/values.

    Returns ``(normalized, ignored)`` where ``ignored`` is the sorted list of
    settings keys AutoSyncAudio does not understand (e.g. ``group_id``,
    ``primary_clip_id``). Those are dropped rather than forwarded: passing any
    unrecognized key makes ``MediaPool.AutoSyncAudio`` silently reject the whole
    call (returns ``False``, nothing links). Callers surface ``ignored`` so the
    rejection is no longer invisible. See core/api_truth.py: MediaPool.AutoSyncAudio.
    """
    if not settings:
        return {}, []
    normalized = {}
    mode_key = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_MODE", "syncMode")
    channel_key = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_CHANNEL_NUMBER", "channelNumber")
    retain_embedded_key = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_RETAIN_EMBEDDED_AUDIO", "retainEmbeddedAudio")
    retain_metadata_key = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_RETAIN_VIDEO_METADATA", "retainVideoMetadata")

    consumed: set = set()

    def _pick(*keys):
        for key in keys:
            if key in settings:
                consumed.add(key)
                return settings[key]
        return None

    # "method" is a natural alias for the sync mode (the tool advertises
    # method="waveform"); accept it alongside syncBy/mode and a pre-resolved key.
    mode = _pick("syncBy", "sync_by", "mode", "method", "syncMode", "sync_mode", mode_key)
    if isinstance(mode, str):
        mode_norm = mode.strip().lower()
        if mode_norm in {"waveform", "audio_waveform", "audio_sync_waveform"}:
            mode = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_WAVEFORM", mode)
        elif mode_norm in {"timecode", "audio_sync_timecode"}:
            mode = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_TIMECODE", mode)
    if mode is not None:
        normalized[mode_key] = mode

    channel = _pick("channelNumber", "channel_number", "channel", channel_key)
    if isinstance(channel, str):
        channel_norm = channel.strip().lower()
        if channel_norm in {"auto", "automatic"}:
            channel = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_CHANNEL_AUTOMATIC", -1)
        elif channel_norm == "mix":
            channel = _resolve_audio_constant(resolve_obj, "AUDIO_SYNC_CHANNEL_MIX", -2)
    if channel is not None:
        normalized[channel_key] = channel

    retain_embedded = _pick("retainEmbeddedAudio", "retain_embedded_audio")
    if retain_embedded is not None:
        normalized[retain_embedded_key] = bool(retain_embedded)
    retain_metadata = _pick("retainVideoMetadata", "retain_video_metadata")
    if retain_metadata is not None:
        normalized[retain_metadata_key] = bool(retain_metadata)

    ignored = sorted(str(key) for key in settings if key not in consumed)
    return normalized, ignored

def _normalize_auto_caption_settings(settings, resolve_obj=None):
    """Translate human-readable subtitle settings (e.g. ``{"language": "korean"}``)
    into live ``SUBTITLE_*``/``AUTO_CAPTION_*`` enum keys/values for
    ``CreateSubtitlesFromAudio``. Returns ``(normalized, ignored)``."""
    return _resolve_enum_settings(resolve_obj, dict(settings or {}), _AUTO_CAPTION_FIELD_SPECS)

def _safe_create_subtitles(tl, p: Dict[str, Any]):
    """CreateSubtitlesFromAudio with enum-resolved settings + readback.

    The raw boolean is unreliable (like AutoSyncAudio), so we verify by reading
    the timeline's subtitle track count before/after and report the real delta.
    """
    settings, ignored = _normalize_auto_caption_settings(p.get("settings"), get_resolve())
    if p.get("dry_run", False):
        return _ok(would_create_subtitles=True, settings=settings, ignored_settings=ignored)

    def _subtitle_track_count():
        try:
            return int(tl.GetTrackCount("subtitle") or 0)
        except Exception:
            return 0

    res = verify_by_readback(
        mutate=lambda: tl.CreateSubtitlesFromAudio(settings),
        observe=_subtitle_track_count,
        snapshot=_subtitle_track_count,
        compare=lambda before, after: {
            "verified": bool((after or 0) > (before or 0)),
            "subtitle_tracks_before": before,
            "subtitle_tracks_after": after,
        },
        label="create_subtitles_from_audio",
        intent={"settings_keys": sorted(settings.keys()) if settings else []},
    )
    return {
        "success": res["success_raw"],
        "verified": res["verified"],
        "subtitle_tracks_before": res.get("subtitle_tracks_before"),
        "subtitle_tracks_after": res.get("subtitle_tracks_after"),
        "settings": settings,
        "ignored_settings": ignored,
    }

def _transcription_capabilities(mp, p: Dict[str, Any]):
    from src.domains.media_pool_ingest.actions import _media_pool_item_summary
    root = mp.GetRootFolder()
    clips = []
    ids = p.get("clip_ids")
    if ids:
        if not isinstance(ids, list):
            return _err("clip_ids must be a list")
        clips = [_find_clip(root, str(clip_id)) for clip_id in ids]
        clips = [clip for clip in clips if clip]
    elif p.get("selected"):
        clips = mp.GetSelectedClips() or []
    current_folder = mp.GetCurrentFolder()
    return {
        "clip_methods": [
            {
                "summary": _media_pool_item_summary(clip),
                "transcribe_audio": _has_method(clip, "TranscribeAudio"),
                "clear_transcription": _has_method(clip, "ClearTranscription"),
                "perform_audio_classification": _has_method(clip, "PerformAudioClassification"),
                "clear_audio_classification": _has_method(clip, "ClearAudioClassification"),
                "analyze_for_intellisearch": _has_method(clip, "AnalyzeForIntellisearch"),
                "analyze_for_slate": _has_method(clip, "AnalyzeForSlate"),
                "remove_motion_blur": _has_method(clip, "RemoveMotionBlur"),
            }
            for clip in clips
        ],
        "folder": {
            "name": current_folder.GetName() if current_folder else None,
            "transcribe_audio": _has_method(current_folder, "TranscribeAudio") if current_folder else False,
            "clear_transcription": _has_method(current_folder, "ClearTranscription") if current_folder else False,
            "perform_audio_classification": _has_method(current_folder, "PerformAudioClassification") if current_folder else False,
            "clear_audio_classification": _has_method(current_folder, "ClearAudioClassification") if current_folder else False,
            "analyze_for_intellisearch": _has_method(current_folder, "AnalyzeForIntellisearch") if current_folder else False,
            "analyze_for_slate": _has_method(current_folder, "AnalyzeForSlate") if current_folder else False,
            "remove_motion_blur": _has_method(current_folder, "RemoveMotionBlur") if current_folder else False,
        },
        "notes": [
            "This action reports capability only; use media_pool_item/folder actions to mutate disposable or approved clips.",
            "Transcription/audio-classification may require Resolve Studio AI components and can run asynchronously.",
            "analyze_for_intellisearch requires the 'AI IntelliSearch' Extra; analyze_for_slate requires 'AI Slate ID'; remove_motion_blur creates new media and is confirm-gated (Resolve 21+).",
        ],
    }

def _subtitle_generation_probe(tl, p: Dict[str, Any]):
    settings, ignored = _normalize_auto_caption_settings(p.get("settings"), get_resolve())
    if not p.get("allow_generate", False):
        return _ok(would_generate=True, settings=settings, ignored_settings=ignored,
                   note="Pass allow_generate=True to call CreateSubtitlesFromAudio.")
    guard = subtitle_generation_guard()
    if guard is not None:
        return _err(
            "CreateSubtitlesFromAudio refused: crashes the Resolve process on this platform",
            code="SUBTITLE_GENERATION_CRASH_GUARD",
            category="unsupported",
            reason=guard["reason"],
            remediation=(
                f"Set {guard['override_env']}=1 to run it anyway (Resolve may die). "
                f"{guard['alternative']} See {guard['issue']}."
            ),
            state=guard,
        )
    if not _has_method(tl, "CreateSubtitlesFromAudio"):
        return _err("CreateSubtitlesFromAudio unavailable")
    res = _run_maybe_background(
        "timeline.create_subtitles_from_audio", p, lambda: _safe_create_subtitles(tl, p)
    )
    if subtitle_generation_override_active() and isinstance(res, dict) and "error" not in res:
        res.setdefault("warnings", []).append(
            "crash guard bypassed via RESOLVE_ALLOW_SUBTITLE_GENERATION: native "
            "CreateSubtitlesFromAudio is proven to kill the Resolve process on this "
            "platform (issue #90). Prefer offline generation + timeline import_srt."
        )
    return res

def _fairlight_boundary_report(proj, mp, tl, p: Dict[str, Any]):
    fairlight_presets = None
    preset_error = None
    resolve_obj = get_resolve()
    if resolve_obj is not None and _has_method(resolve_obj, "GetFairlightPresets"):
        try:
            fairlight_presets = _ser(resolve_obj.GetFairlightPresets() or [])
        except Exception as exc:
            preset_error = str(exc)
    return {
        "capabilities": _audio_capabilities(),
        "track": _audio_track_probe(tl, p),
        "item": _probe_audio_item(tl, p) if int(tl.GetTrackCount(p.get("track_type", "audio")) or 0) else None,
        "voice_isolation": _voice_isolation_capabilities(tl, p),
        "audio_mapping": _audio_mapping_report(mp, tl, p),
        "transcription": _transcription_capabilities(mp, p),
        "fairlight_presets": {"value": fairlight_presets, "error": preset_error} if preset_error else fairlight_presets,
        "project_methods": _callable_method_names(proj, ["InsertAudioToCurrentTrackAtPlayhead", "ApplyFairlightPresetToCurrentTimeline"]),
    }


